import { cacheTag } from "next/cache";

export type Post = {
  id: number;
  title: string;
  content: string;
  createdAt: Date;
};

// In-memory store (in production, this would be a database)
const posts: Post[] = [
  {
    id: 1,
    title: "Hello World",
    content: "This is the first post.",
    createdAt: new Date("2026-01-01"),
  },
  {
    id: 2,
    title: "Second Post",
    content: "Another post to demonstrate the list.",
    createdAt: new Date("2026-06-15"),
  },
];

let nextId = 3;

export function addPost(title: string, content: string): Post {
  const post: Post = { id: nextId++, title, content, createdAt: new Date() };
  posts.push(post);
  return post;
}

export async function getPosts(): Promise<Post[]> {
  "use cache";

  // Tag this cached data with "posts" so it can be invalidated on demand
  cacheTag("posts");

  // Simulate a small delay to demonstrate caching behavior
  await new Promise((resolve) => setTimeout(resolve, 500));

  return [...posts].reverse();
}

"use server";

import { revalidateTag } from "next/cache";
import { addPost } from "./lib/posts";

export async function createPost(formData: FormData) {
  const title = formData.get("title") as string;
  const content = formData.get("content") as string;

  if (!title || !content) {
    throw new Error("Title and content are required");
  }

  // Persist the new post
  addPost(title, content);

  // Hard-invalidate the "posts" cache tag so the next page load
  // re-fetches fresh data instead of serving stale cached content.
  revalidateTag("posts");
}

import { getPosts } from "./lib/posts";
import { createPost } from "./actions";

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: "0 auto", padding: "2rem 1rem" }}>
      <h1>Posts</h1>

      <section style={{ marginBottom: "2rem" }}>
        <h2>Create a new post</h2>
        <form action={createPost}>
          <div style={{ marginBottom: "0.5rem" }}>
            <label htmlFor="title">
              Title
              <input
                id="title"
                name="title"
                type="text"
                required
                style={{ display: "block", width: "100%", marginTop: 4 }}
              />
            </label>
          </div>
          <div style={{ marginBottom: "0.5rem" }}>
            <label htmlFor="content">
              Content
              <textarea
                id="content"
                name="content"
                required
                rows={3}
                style={{ display: "block", width: "100%", marginTop: 4 }}
              />
            </label>
          </div>
          <button type="submit">Create Post</button>
        </form>
      </section>

      <section>
        <h2>All posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul style={{ listStyle: "none", padding: 0 }}>
            {posts.map((post) => (
              <li
                key={post.id}
                style={{
                  border: "1px solid #ccc",
                  borderRadius: 6,
                  padding: "0.75rem 1rem",
                  marginBottom: "0.75rem",
                }}
              >
                <h3 style={{ margin: "0 0 0.25rem" }}>{post.title}</h3>
                <p style={{ margin: 0, color: "#555" }}>{post.content}</p>
                <small style={{ color: "#888" }}>
                  {post.createdAt.toLocaleDateString()}
                </small>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}

